static int **insertInterval(int **intervalPtrs, int n, int newInterval[2], int *returnSize, int **resultDataOut) {
    // worst-case result size n+1
    int maxR = n + 1;
    int *resData = malloc(sizeof(int) * 2 * maxR);
    if (!resData) { perror("malloc"); exit(1); }
    int **resPtrs = malloc(sizeof(int*) * maxR);
    if (!resPtrs) { perror("malloc"); exit(1); }

    int ri = 0; // result index
    int i = 0;

    // 1) add intervals before new
    while (i < n && intervalPtrs[i][1] < newInterval[0]) {
        resData[2*ri + 0] = intervalPtrs[i][0];
        resData[2*ri + 1] = intervalPtrs[i][1];
        resPtrs[ri] = &resData[2*ri];
        ri++; i++;
    }

    // 2) merge overlapping
    int ms = newInterval[0];
    int me = newInterval[1];
    while (i < n && intervalPtrs[i][0] <= me) {
        if (intervalPtrs[i][0] < ms) ms = intervalPtrs[i][0];
        if (intervalPtrs[i][1] > me) me = intervalPtrs[i][1];
        i++;
    }
    // push merged
    resData[2*ri + 0] = ms;
    resData[2*ri + 1] = me;
    resPtrs[ri] = &resData[2*ri];
    ri++;

    // 3) add remaining
    while (i < n) {
        resData[2*ri + 0] = intervalPtrs[i][0];
        resData[2*ri + 1] = intervalPtrs[i][1];
        resPtrs[ri] = &resData[2*ri];
        ri++; i++;
    }

    *returnSize = ri;
    *resultDataOut = resData;
    return resPtrs;
}

