class Solution {
    public List<int[]> insertInterval(List<int[]> intervalList, int[] newIntervalValue) {
        List<int[]> result = new ArrayList<>();
        int i = 0, n = intervalList.size();

        // 1. Add all intervals that end before new interval starts
        while (i < n && intervalList.get(i)[1] < newIntervalValue[0]) {
            result.add(intervalList.get(i));
            i++;
        }

        // 2. Merge all overlapping intervals
        while (i < n && intervalList.get(i)[0] <= newIntervalValue[1]) {
            newIntervalValue[0] = Math.min(newIntervalValue[0], intervalList.get(i)[0]);
            newIntervalValue[1] = Math.max(newIntervalValue[1], intervalList.get(i)[1]);
            i++;
        }

        // Add merged interval
        result.add(newIntervalValue);

        // 3. Add all remaining intervals
        while (i < n) {
            result.add(intervalList.get(i));
            i++;
        }

        return result;
    }
}

